<section class="page-head"><h1>Categorías</h1><p>Podés crear, editar, eliminar y asignar una portada local sin tocar la estructura de Supabase.</p></section>
<form class="panel category-form" method="post" action="<?= site_url('admin/categorias/crear') ?>" enctype="multipart/form-data"><?= csrf_field() ?><h2>Nueva categoría</h2><div class="edit-grid two"><label>Nombre<input name="nombre" required placeholder="Ej: Indumentaria superior"></label><label>Orden<input name="orden" type="number" value="0"></label></div><div class="edit-grid two"><label>Portada<input name="portada" type="file" accept="image/*"></label><div class="check-grid"><label><input type="checkbox" name="visible" checked> Visible</label><label><input type="checkbox" name="usa_talles"> Usa talles</label></div></div><button class="btn primary">Crear categoría</button></form>
<div class="category-admin-grid"><?php foreach($categorias as $c): ?><article class="category-admin-card"><img src="<?= e($c['imagen']) ?>" alt=""><div class="info"><h3><?= e($c['nombre']) ?></h3><span>ID #<?= e($c['id']) ?> · <?= !empty($c['visible'])?'Visible':'Oculta' ?><?= !empty($c['usa_talles'])?' · Usa talles':'' ?></span></div><div class="tools"><button type="button" data-edit-category>Editar</button><form method="post" action="<?= site_url('admin/categorias/eliminar/'.$c['id']) ?>" data-confirm-title="Confirmar eliminación" data-confirm-message="¿Deseás eliminar esta categoría? Esta acción no se puede deshacer."><?= csrf_field() ?><button>Eliminar</button></form></div><form hidden class="edit-cat" method="post" action="<?= site_url('admin/categorias/actualizar/'.$c['id']) ?>" enctype="multipart/form-data"><div class="edit-cat-box"><?= csrf_field() ?><input name="nombre" value="<?= e($c['nombre']) ?>"><input name="orden" type="number" value="<?= e($c['orden'] ?? 0) ?>"><label><input type="checkbox" name="visible" <?= !empty($c['visible'])?'checked':'' ?>> Visible</label><label><input type="checkbox" name="usa_talles" <?= !empty($c['usa_talles'])?'checked':'' ?>> Usa talles</label><input name="portada" type="file" accept="image/*"><div class="actions"><button class="btn primary">Guardar</button><button class="btn outline" type="button" data-close-category>Cancelar</button></div></div></form></article><?php endforeach; ?></div>
